WHERE NOT EXISTS (SELECT 1 FROM products WHERE sku = 'SKIRT-76' OR (slug = 'orange-net-skirt-with-gold-border' AND store_id = '9403fc00-1042-4770-a64b-08f196a58457'::uuid));

